import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import {
  LayoutDashboard,
  Key,
  CreditCard,
  BarChart3,
  Receipt,
  Rocket,
  Settings,
  Shield,
  Users,
  Network,
  Ticket,
  Wrench,
  FileText,
} from 'lucide-react';
import { cn } from '../../lib/utils';
import { isAdmin } from '../../helpers';
import { useTranslation } from 'react-i18next';

/* Figma sidebar: 4 main items */
const sidebarItems = [
  { label: 'CodingPlan', to: '/dashboard', icon: Key },
  { label: '用量', to: '/usage', icon: BarChart3 },
  { label: '账单记录', to: '/billing', icon: Receipt },
  { label: '套餐', to: '/subscription', icon: CreditCard },
];

const adminSidebarItemKeys = [
  { key: 'nav.sidebar.admin_dashboard', to: '/admin/dashboard', icon: LayoutDashboard },
  { key: 'nav.sidebar.user_management', to: '/user', icon: Users },
  { key: 'nav.sidebar.plan_management', to: '/admin/plans', icon: CreditCard },
  { key: 'nav.sidebar.channel_management', to: '/channel', icon: Network },
  { key: 'nav.sidebar.redemption', to: '/redemption', icon: Ticket },
  { key: 'nav.sidebar.logs', to: '/log', icon: FileText },
  { key: 'nav.sidebar.system_settings', to: '/setting', icon: Wrench },
];

/* Also export extra items for routes that still exist but aren't in main sidebar */
const extraItems = [
  { to: '/keys', icon: Key },
  { to: '/booster', icon: Rocket },
  { to: '/settings', icon: Settings },
];

export const SidebarNav = ({ className }) => {
  const location = useLocation();
  const userIsAdmin = isAdmin();
  const { t } = useTranslation();

  return (
    <nav className={cn('flex flex-col gap-3', className)}>
      {sidebarItems.map((item) => {
        const Icon = item.icon;
        const isActive = location.pathname === item.to;
        return (
          <Link
            key={item.to}
            to={item.to}
            className={cn(
              'flex items-center gap-2 h-10 px-5 text-sm font-normal no-underline transition-colors',
              isActive
                ? 'bg-[#f0f5ff] text-[#4362ff]'
                : 'text-[#344256] hover:bg-[#f8fafc]'
            )}
          >
            <Icon className='h-3.5 w-3.5 flex-shrink-0' />
            <span className='flex-1'>{item.label}</span>
          </Link>
        );
      })}
      {userIsAdmin && (
        <>
          <div className='my-1 border-t border-[#e1e7ef]' />
          <div className='flex items-center gap-2 px-5 py-1'>
            <Shield className='h-3.5 w-3.5 text-[#9eacbf]' />
            <span className='text-xs font-medium text-[#9eacbf] uppercase tracking-wider'>
              {t('nav.sidebar.admin_section')}
            </span>
          </div>
          {adminSidebarItemKeys.map((item) => {
            const Icon = item.icon;
            const isActive = location.pathname === item.to;
            return (
              <Link
                key={item.to}
                to={item.to}
                className={cn(
                  'flex items-center gap-2 h-10 px-5 text-sm font-normal no-underline transition-colors',
                  isActive
                    ? 'bg-[#f0f5ff] text-[#4362ff]'
                    : 'text-[#344256] hover:bg-[#f8fafc]'
                )}
              >
                <Icon className='h-3.5 w-3.5 flex-shrink-0' />
                <span className='flex-1'>{t(item.key)}</span>
              </Link>
            );
          })}
        </>
      )}
    </nav>
  );
};

const ConsoleSidebar = () => {
  return (
    <aside className='hidden md:flex md:w-[220px] md:flex-col md:flex-shrink-0 bg-white border-r border-[#c8d5e5]'>
      <div className='flex-1 overflow-y-auto py-3 px-2'>
        <SidebarNav />
      </div>
    </aside>
  );
};

export default ConsoleSidebar;
