import React, { useContext } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { UserContext } from '../../context/User';
import { API, showSuccess } from '../../helpers';
import { Button } from '../ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '../ui/dropdown-menu';
import { Sheet, SheetContent, SheetTrigger } from '../ui/sheet';
import { LogOut, Menu } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { SidebarNav } from './ConsoleSidebar';

const ConsoleTopBar = () => {
  const [userState, userDispatch] = useContext(UserContext);
  const navigate = useNavigate();
  const { t } = useTranslation();

  const logout = async () => {
    await API.get('/api/user/logout');
    showSuccess(t('nav.logout_success'));
    userDispatch({ type: 'logout' });
    localStorage.removeItem('user');
    navigate('/login');
  };

  const username = userState.user?.username || t('nav.user_default');

  return (
    <header className='sticky top-0 z-30 flex h-14 items-center bg-white border-b border-[#e1e7ef] px-6'>
      {/* Mobile menu */}
      <Sheet>
        <SheetTrigger asChild>
          <Button variant='outline' size='icon' className='shrink-0 md:hidden mr-3'>
            <Menu className='h-5 w-5' />
            <span className='sr-only'>{t('nav.toggle_menu')}</span>
          </Button>
        </SheetTrigger>
        <SheetContent side='left' className='flex flex-col'>
          <nav className='grid gap-2 text-lg font-medium'>
            <Link to='/' className='flex items-center gap-2 text-lg font-semibold mb-4'>
              <img src={process.env.PUBLIC_URL + '/logo-dark.svg'} alt='Alaya Code' className='h-6' />
              <span className='font-mono font-medium text-xl text-[#090e1a]'>Alaya Code</span>
            </Link>
            <SidebarNav />
          </nav>
        </SheetContent>
      </Sheet>

      {/* Logo */}
      <Link to='/' className='hidden md:flex items-center gap-1 no-underline'>
        <img src={process.env.PUBLIC_URL + '/logo-dark.svg'} alt='Alaya Code' className='h-6' />
        <span className='font-mono font-medium text-xl text-[#090e1a] leading-7'>Alaya Code</span>
      </Link>

      <div className='flex-1' />

      {/* Right side: 文档 + avatar */}
      <div className='flex items-center h-full'>
        <Link
          to='/docs'
          className='flex items-center h-full px-3 text-sm text-[#090e1a] no-underline hover:text-xyz-blue-6 transition-colors'
        >
          文档
        </Link>
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <button className='flex items-center gap-2 h-full px-6 hover:bg-[#f8fafc] transition-colors cursor-pointer border-0 bg-transparent'>
              <div className='w-6 h-6 rounded-full bg-[#e6edff] flex items-center justify-center'>
                <svg width='14' height='14' viewBox='0 0 24 24' fill='none'>
                  <circle cx='12' cy='8' r='4' fill='#4362ff' opacity='0.6' />
                  <path d='M4 20c0-4 3.6-7 8-7s8 3 8 7' fill='#4362ff' opacity='0.6' />
                </svg>
              </div>
              <span className='text-sm text-[#090e1a]'>{username}</span>
            </button>
          </DropdownMenuTrigger>
          <DropdownMenuContent className='w-48' align='end' forceMount>
            <div className='flex items-center gap-2 p-2'>
              <div className='flex flex-col space-y-1 leading-none'>
                <p className='text-sm font-medium'>{username}</p>
              </div>
            </div>
            <DropdownMenuSeparator />
            <DropdownMenuItem onClick={logout}>
              <LogOut className='mr-2 h-4 w-4' />
              <span>{t('nav.logout')}</span>
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      </div>
    </header>
  );
};

export default ConsoleTopBar;
